	private void ReconnectButtonPressed(ButtonEventArgs args)
	{
		if (!_redial || !_state.Redial())
		{
			_state.RetryConnect();
		}
	}

	private void CopyButtonPressed(ButtonEventArgs args)
	{
		CopyText(ConnectFailReason.Text);
	}

	private void CopyButtonDisconnectedPressed(ButtonEventArgs args)
	{
		CopyText(DisconnectReason.Text);
	}

	private void CopyText(string? text)
	{
		if (!string.IsNullOrEmpty(text))
		{
			_clipboard.SetText(text);
		}
	}

	private void ConnectFailReasonChanged(string? reason)
	{
		ConnectFailReason.SetMessage((reason == null) ? "" : Loc.GetString("connecting-fail-reason", new(string, object)[1] { ("reason", reason) }), (Color?)null);
	}

	private void LastNetDisconnectedArgsChanged(NetDisconnectedArgs? args)
	{
		HandleDisconnectReason((INetStructuredReason?)(object)args);
	}

	private void HandleDisconnectReason(INetStructuredReason? reason)
	{
		if (reason == null)
		{
			_waitTime = 0f;
			_redial = false;
			return;
		}
		_redial = reason.RedialFlag;
		int? num = reason.Message.Int32Of("delay");
		if (num.HasValue)
		{
			int valueOrDefault = num.GetValueOrDefault();
			_waitTime = valueOrDefault;
		}
		else if (_redial)
		{
			_waitTime = 15f;
		}
	}

	private void ChangeLoginTip()
	{
		string cVar = _cfg.GetCVar<string>(CCVars.LoginTipsDataset);
		LocalizedDatasetPrototype localizedDatasetPrototype = default(LocalizedDatasetPrototype);
		bool flag = _prototype.TryIndex<LocalizedDatasetPrototype>(cVar, ref localizedDatasetPrototype);
		((Control)LoginTips).Visible = flag;
		if (flag)
		{
			LocalizedDatasetValues values = localizedDatasetPrototype.Values;
			if (values.Count != 0)
			{
				int num = _random.Next(values.Count);
				string text = values[num];
				LoginTip.SetMessage(Loc.GetString(text), (Color?)null);
				LoginTipTitle.Text = Loc.GetString("connecting-window-tip", new(string, object)[1] { ("numberTip", num) });
			}
		}
	}

	protected override void FrameUpdate(FrameEventArgs args)
	{
		//IL_0001: Unknown result type (might be due to invalid IL or missing references)
		((Control)this).FrameUpdate(args);
		Button val = ((_state.CurrentPage == LauncherConnecting.Page.ConnectFailed) ? RetryButton : ReconnectButton);
		_waitTime -= ((FrameEventArgs)(ref args)).DeltaSeconds;
		if (_waitTime <= 0f)
		{
			((BaseButton)val).Disabled = false;
			string text = (_redial ? "connecting-redial" : ((_state.CurrentPage == LauncherConnecting.Page.ConnectFailed) ? "connecting-reconnect" : "connecting-retry"));
			val.Text = Loc.GetString(text);
		}
		else
		{
			((BaseButton)val).Disabled = true;
			val.Text = Loc.GetString("connecting-redial-wait", new(string, object)[1] { ("time", _waitTime.ToString("00.000")) });
		}
	}

	private void OnPageChanged(LauncherConnecting.Page page)
	{
		((Control)ConnectingStatus).Visible = page == LauncherConnecting.Page.Connecting;
		((Control)ConnectFail).Visible = page == LauncherConnecting.Page.ConnectFailed;
		((Control)Disconnected).Visible = page == LauncherConnecting.Page.Disconnected;
		if (page == LauncherConnecting.Page.Disconnected)
		{
			DisconnectReason.Text = _state.LastDisconnectReason;
		}
	}

	private void ConnectionStateChanged(ClientConnectionState state)
	{
		//IL_001e: Unknown result type (might be due to invalid IL or missing references)
		ConnectStatus.Text = Loc.GetString($"connecting-state-{state}");
	}

